import TOMATO_RULES_TEXT from './tomatoRules'
import { ROLES } from './roles'
import { TASKS, buildContextBlock } from './tasks'
import { LOGIC_OUTPUT, REMOVE_AI_OUTPUT, RHYTHM_OUTPUT, SLAP_FACE_OUTPUT } from './outputs'

export { TOMATO_RULES_TEXT, ROLES, TASKS, buildContextBlock }
export { LOGIC_OUTPUT, REMOVE_AI_OUTPUT, RHYTHM_OUTPUT, SLAP_FACE_OUTPUT }

// 快捷函数：构建逻辑校验的 prompt
export function buildLogicCheckPrompt(
  taskType: 'power' | 'timeline' | 'character' | 'causal',
  chapterContent: string,
  context: {
    facts?: string
    characters?: string
    worldRules?: string
  }
): string {
  const taskKey = taskType + 'Check' as keyof typeof TASKS
  const task = TASKS[taskKey]
  const contextBlock = buildContextBlock({
    chapterContent,
    facts: context.facts,
    characters: context.characters,
    worldRules: context.worldRules,
  })

  return task.role_persona + '\n\n' + contextBlock + '\n' + task.task
}

// 快捷函数：构建去AI味 prompt
export function buildRemoveAIPrompt(
  selectedText: string,
  context: {
    facts?: string
    characters?: string
  }
): string {
  const task = TASKS.removeAITrace
  const contextBlock = buildContextBlock({
    chapterContent: '',
    facts: context.facts,
    characters: context.characters,
  })

  const prompt = task.task.replace('{selectedText}', selectedText)
  return task.role_persona + '\n\n' + contextBlock + '\n' + prompt
}

// 快捷函数：构建节奏检测 prompt
export function buildRhythmCheckPrompt(
  chapterContent: string,
  chapterRange: { start: number; end: number }
): string {
  const task = TASKS.rhythmCheck
  const contextBlock = buildContextBlock({
    chapterContent,
    chapterRange,
  })

  return task.role_persona + '\n\n' + contextBlock + '\n' + task.task
}

export default {
  TOMATO_RULES_TEXT,
  ROLES,
  TASKS,
  buildContextBlock,
  buildLogicCheckPrompt,
  buildRemoveAIPrompt,
  buildRhythmCheckPrompt,
}

